/**
 * Viper Player — self-hosted adapter for Horizon Movies
 * Implements: new Viper(containerId, { source, autoplay })
 * source: a direct video URL (MP4) or a TMDB ID (falls back to proxy iframe)
 */
(function (global) {
  "use strict";

  var CSS = [
    "* { margin:0; padding:0; box-sizing:border-box; }",
    "body { background:#000; width:100vw; height:100vh; overflow:hidden; }",
    "#viper-player { width:100%; height:100%; position:relative; background:#000; }",
    ".viper-loader {",
    "  position:absolute; inset:0; display:flex; flex-direction:column;",
    "  align-items:center; justify-content:center; background:#0d0d0d; z-index:2;",
    "}",
    ".viper-spinner {",
    "  width:44px; height:44px; border:3px solid rgba(168,85,247,.2);",
    "  border-top-color:#a855f7; border-radius:50%;",
    "  animation:viper-spin .8s linear infinite;",
    "}",
    "@keyframes viper-spin { to { transform:rotate(360deg); } }",
    ".viper-logo {",
    "  margin-top:16px; font-family:sans-serif; font-size:13px;",
    "  color:rgba(168,85,247,.7); letter-spacing:.12em; text-transform:uppercase;",
    "}",
    ".viper-err {",
    "  position:absolute; inset:0; display:flex; flex-direction:column;",
    "  align-items:center; justify-content:center; background:#0d0d0d;",
    "  color:rgba(255,255,255,.4); font-family:sans-serif; font-size:13px;",
    "  gap:8px; z-index:2;",
    "}",
    ".viper-err b { color:rgba(255,255,255,.65); font-size:15px; }",
    "video { position:absolute; inset:0; width:100%; height:100%; background:#000; }",
    ".viper-frame { position:absolute; inset:0; width:100%; height:100%; border:0; }",
  ].join("\n");

  function Viper(containerId, opts) {
    opts = opts || {};

    var el =
      typeof containerId === "string"
        ? document.getElementById(containerId)
        : containerId;
    if (!el) {
      console.warn("[Viper] container not found:", containerId);
      return;
    }

    var src = String(opts.source || "").trim();

    this._el = el;
    this._autoplay = opts.autoplay !== false;

    if (src.startsWith("http")) {
      this._renderVideo(src);
    } else {
      this._renderProxy(src);
    }
  }

  Viper.prototype._loader = function (el) {
    var loader = document.createElement("div");
    loader.className = "viper-loader";
    loader.innerHTML =
      '<div class="viper-spinner"></div><div class="viper-logo">Viper Player</div>';
    el.appendChild(loader);
    return loader;
  };

  Viper.prototype._renderVideo = function (src) {
    var self = this;
    var el = this._el;
    el.innerHTML = "";
    el.style.cssText = "position:relative;width:100%;height:100%;background:#000;";

    var loader = this._loader(el);

    var vid = document.createElement("video");
    vid.controls = true;
    vid.autoplay = this._autoplay;
    vid.style.opacity = "0";
    vid.style.transition = "opacity .3s ease";

    var src_ = document.createElement("source");
    src_.src = src;
    src_.type = "video/mp4";
    vid.appendChild(src_);

    vid.oncanplay = function () {
      loader.style.display = "none";
      vid.style.opacity = "1";
    };

    vid.onerror = function () {
      self._showError(el, "Could not load video.");
    };

    setTimeout(function () {
      if (loader.style.display !== "none") {
        loader.style.display = "none";
        vid.style.opacity = "1";
      }
    }, 10000);

    el.appendChild(vid);
    this._vid = vid;
  };

  Viper.prototype._renderProxy = function (tmdbId) {
    var self = this;
    var el = this._el;
    el.innerHTML = "";
    el.style.cssText = "position:relative;width:100%;height:100%;background:#000;";

    var loader = this._loader(el);

    var frame = document.createElement("iframe");
    frame.className = "viper-frame";
    frame.src = "/api/movie-player/" + tmdbId;
    frame.allowFullscreen = true;
    frame.setAttribute(
      "allow",
      "autoplay; fullscreen; encrypted-media; picture-in-picture"
    );
    frame.style.opacity = "0";
    frame.style.transition = "opacity .3s ease";

    frame.onload = function () {
      loader.style.display = "none";
      frame.style.opacity = "1";
    };

    frame.onerror = function () {
      self._showError(el, "Player failed to load.");
    };

    setTimeout(function () {
      if (loader.style.display !== "none") {
        loader.style.display = "none";
        frame.style.opacity = "1";
      }
    }, 8000);

    el.appendChild(frame);
    this._frame = frame;
  };

  Viper.prototype._showError = function (el, msg) {
    el.innerHTML =
      '<div class="viper-err"><b>Viper Player</b><span>' + msg + "</span></div>";
  };

  Viper.prototype.destroy = function () {
    if (this._el) this._el.innerHTML = "";
  };

  global.Viper = Viper;
})(window);
